let metadata = $json.metadata || {};

if (typeof metadata === 'string') {
  try {
    metadata = JSON.parse(metadata);
  } catch (e) {
    metadata = {};
  }
}

return [{
  json: {
    ...$json,
    metadata,
    outbox_id: $json.outbox_id,
    response_recipient: $json.recipient,
    response_body: $json.body,
    reply_markup: $json.reply_markup || null,
    bot_token: $json.bot_token,
    chat_id: $json.recipient,

    tts_required: Boolean(metadata.tts_required),
    tts_text: metadata.tts_text || null,

    visual_required: Boolean(metadata.visual_required),
    visual_prompt: metadata.visual_prompt || null,
    visual_title: metadata.visual_title || null,
    visual_score: metadata.visual_score ?? null,
    visual_candidate_name: metadata.visual_candidate_name || null,
    visual_vacancy_title: metadata.visual_vacancy_title || null
  }
}];

let metadata = $json.metadata || {};

if (typeof metadata === 'string') {
  try {
    metadata = JSON.parse(metadata);
  } catch (e) {
    metadata = {};
  }
}

const body = String($json.body || '');
let ttsText = String($json.tts_text || metadata.tts_text || '');

if (!ttsText.trim()) {
  ttsText = body
    .replace(/\n+/g, ' ')
    .replace(/[•📊💼📝✅ℹ️📞🔄📄]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

if (ttsText.length > 500) {
  ttsText = ttsText.slice(0, 500) + '...';
}

return [{
  json: {
    ...$json,
    outbox_id: $json.outbox_id,
    intake_event_id: $json.intake_event_id,
    candidate_id: $json.candidate_id,
    recipient: $json.recipient,
    bot_token: $json.bot_token || $('Build context after outbox').first().json.bot_token,
    tts_required: $json.tts_required,
    visual_required: $json.visual_required,
    visual_prompt: $json.visual_prompt,
    visual_title: $json.visual_title,
    visual_score: $json.visual_score,
    visual_candidate_name: $json.visual_candidate_name,
    visual_vacancy_title: $json.visual_vacancy_title,
    tts_text: ttsText || 'Результат анализа готов.'
  }
}];

let metadata = $json.metadata || {};

if (typeof metadata === 'string') {
  try {
    metadata = JSON.parse(metadata);
  } catch (e) {
    metadata = {};
  }
}

const fallbackPrompt =
  'Современная HR-карточка результата подбора. ' +
  'Сделай чистую корпоративную инфографику по результату анализа резюме. ' +
  'Стиль: светлый фон, аккуратный UI, технологичный HR AI assistant. ' +
  'Без мелкого текста и без перегруженных деталей.';

const visualPrompt = String(
  $json.visual_prompt ||
  metadata.visual_prompt ||
  fallbackPrompt
).trim();

return [{
  json: {
    ...$json,

    outbox_id: $json.outbox_id,
    intake_event_id: $json.intake_event_id,
    candidate_id: $json.candidate_id,
    recipient: $json.recipient,

    bot_token:
      $json.bot_token ||
      $('Build context after outbox').first().json.bot_token,

    visual_prompt: visualPrompt,

    visual_title:
      $json.visual_title ||
      metadata.visual_title ||
      null,

    visual_score:
      $json.visual_score ??
      metadata.visual_score ??
      null,

    visual_candidate_name:
      $json.visual_candidate_name ||
      metadata.visual_candidate_name ||
      null,

    visual_vacancy_title:
      $json.visual_vacancy_title ||
      metadata.visual_vacancy_title ||
      null,

    image_body: {
      model: 'gpt-image-1',
      prompt: visualPrompt,
      size: '1024x1024'
    }
  }
}];

const b64 =
  $json.data?.[0]?.b64_json ||
  $json.data?.[0]?.image_base64 ||
  $json.b64_json ||
  '';

if (!b64) {
  throw new Error('OpenAI image response does not contain base64 image');
}

const ctx = $('Build visual payload').first().json;

return [{
  json: {
    ...ctx,
    visual_image_ready: true
  },
  binary: {
    data: {
      data: b64,
      mimeType: 'image/png',
      fileName: 'hr_result_card.png'
    }
  }
}];
